generated_oml:
// Sensing Components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor (I_M) mounted on the permanent‑magnet synchronous motor of the first rotary joint axis."
    DTDFVocab:producedData MotorCurrentTransmission
]

instance MotorEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Motor encoder measuring the output angle of the permanent‑magnet synchronous motor shaft."
    DTDFVocab:producedData MotorOutputAngleTransmission
]

instance GearboxEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder placed behind the cycloidal gearbox to measure the output angle of the gearbox."
    DTDFVocab:producedData MotorOutputAngleTransmission
]

// Physical-to-virtual interaction via MQTT
instance MotorCurrentTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorOutputAngleTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoderSensor, GearboxEncoderSensor
]

instance DerivedTorqueTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor, MotorEncoderSensor
]

instance AngularVelocityTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoderSensor
]

// Data Traces
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Measured motor current I_M time‑series recorded via MQTT."
    DTDFVocab:inputTo FrictionIdentificationEnabler
    DTDFVocab:fromData MotorCurrentTransmission
]

instance OutputAngleData : DTDFVocab:Data [
    base:desc "Measured output angle time‑series from motor and gearbox encoders recorded via MQTT."
    DTDFVocab:inputTo FrictionIdentificationEnabler
    DTDFVocab:fromData MotorOutputAngleTransmission
]

instance DerivedTorqueData : DTDFVocab:Data [
    base:desc "Derived torque τ time‑series calculated from motor current and encoder data."
    DTDFVocab:inputTo FrictionIdentificationEnabler
    DTDFVocab:fromData DerivedTorqueTransmission
]

instance AngularVelocityData : DTDFVocab:Data [
    base:desc "Derived angular velocity ω time‑series calculated from encoder data."
    DTDFVocab:inputTo FrictionIdentificationEnabler
    DTDFVocab:fromData AngularVelocityTransmission
]

// Simulation Models
instance MotorSimulationModel : DTDFVocab:Model [
    base:desc "Executable Simulink model of the permanent‑magnet synchronous motor."
    DTDFVocab:inputTo FrictionIdentificationEnabler
]

instance GearwheelSimulationModel : DTDFVocab:Model [
    base:desc "Simulink model of the gearwheel transmission within the rotary joint axis."
    DTDFVocab:inputTo FrictionIdentificationEnabler
]

instance GearboxSimulationModel : DTDFVocab:Model [
    base:desc "Simulink model of the cycloidal gearbox used in the MABI MAX 100."
    DTDFVocab:inputTo FrictionIdentificationEnabler
]

instance FrictionModel : DTDFVocab:Model [
    base:desc "White‑box analytical friction model combining Coulomb‑Viscous, Stribeck, Dahl, and LuGre representations."
    DTDFVocab:inputTo FrictionIdentificationEnabler
]

// Enablers
instance FrictionIdentificationEnabler : DTDFVocab:Enabler [
    base:desc "Real‑time friction identification enabler integrating measured and simulated traces to continuously calibrate static, kinetic, and viscous friction parameters."
    DTDFVocab:enables RealTimeFrictionEstimationService
]

// Services
instance RealTimeFrictionEstimationService : DTDFVocab:Service [
    base:desc "Service that performs continuous identification and calibration of joint friction parameters using a hybrid white‑/black‑box approach."
    DTDFVocab:provides FrictionParameterUpdateInsight, PositionErrorReductionAction
]

// Insights and Actions
instance FrictionParameterUpdateInsight : DTDFVocab:Insight [
    base:desc "Insight reporting the updated friction parameters for static, kinetic, and viscous effects derived from real‑time estimation."
]

instance PositionErrorReductionAction : DTDFVocab:Action [
    base:desc "Automatic action that updates the robot controller inputs with the latest friction parameters to reduce position errors."
    DTDFVocab:IsAutomatic true
]

// Physical Components
instance MotorComponent : DTDFVocab:Component [
    base:desc "Permanent‑magnet synchronous motor constituting the actuator of the first rotary joint axis."
]

instance GearTransmissionComponent : DTDFVocab:Component [
    base:desc "Gearwheel transmission that connects the motor shaft to the cycloidal gearbox."
]

instance CycloidalGearboxComponent : DTDFVocab:Component [
    base:desc "Cycloidal gearbox providing final gear reduction for the first rotary joint axis."
]

// Environment
instance DigitalTwinEnvironment : DTDFVocab:Environment [
    base:contains MotorComponent, GearTransmissionComponent, CycloidalGearboxComponent,
           MotorCurrentSensor, MotorEncoderSensor, GearboxEncoderSensor,
           MotorCurrentTransmission, MotorOutputAngleTransmission, DerivedTorqueTransmission, AngularVelocityTransmission,
           MotorCurrentData, OutputAngleData, DerivedTorqueData, AngularVelocityData,
           MotorSimulationModel, GearwheelSimulationModel, GearboxSimulationModel, FrictionModel,
           FrictionIdentificationEnabler, RealTimeFrictionEstimationService,
           FrictionParameterUpdateInsight, PositionErrorReductionAction
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "The DT operates in real‑time, processing live data streams synchronous with the robot’s operating cycle (maximum joint speed 75 deg/s) and continuously updating friction models during operation."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The DT constellation comprises the physical asset (first axis), the digital shadow (data traces and simulation models), the data ingestion layer (MQTT broker and AAS interfaces), and the visualization layer (dashboard). All components interact through one‑way data flow from physical to virtual, with computational processing performed by the digital shadow."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The DT spans all three lifecycle phases: design (ideal, friction‑free simulation models), manufacture (actual robot and sensor data), and operation (continuous identification and refinement of friction models during live use)."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Model validity ensured by traceability of every data point back to its source and computational model; continuous identification keeps models aligned with lived wear and temperature effects; verification of simulation against measured torque and velocity; analytical white‑box models provide physical interpretability while black‑box models capture residual behaviours; uncertainty handled through ongoing calibration but explicit error bounds not quantified."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Physical to virtual data are transmitted over MQTT messaging protocol; semantic publishing via Asset Administration Shells (AAS); one‑way data flow from robot to digital shadow; no bi‑directional network link described."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of SysML v1.7 for structural and behavioral modeling; adoption of MBSE methods such as RFLP, OOSEM, SPES, SMArDT; Digital Shadow Reference Model (DSRM) as reference architecture; Asset Administration Shells (AAS) conform to the Open Digital Architecture of Industry 4.0; no mention of IEC 62443 compliance."
]
